Spawn coins at the pickup point and animate them to the counter position:

```typescript
function collectCoin(parent: cc.Node, fromPos: cc.Point, toPos: cc.Point, onDone: () => void): void {
    const coin = new cc.Sprite('coin.png');
    coin.setPosition(fromPos);
    coin.setScale(1.2);
    parent.addChild(coin, 100);

    const midX = (fromPos.x + toPos.x) / 2;
    const midY = Math.max(fromPos.y, toPos.y) + 80;

    coin.runAction(cc.sequence(
        cc.spawn(
            cc.bezierTo(0.6, [
                cc.p(midX, midY),
                cc.p(toPos.x, toPos.y + 20),
                toPos
            ]).easing(cc.easeIn(1.5)),
            cc.scaleTo(0.6, 0.5),
            cc.sequence(cc.delayTime(0.3), cc.fadeOut(0.3))
        ),
        cc.callFunc(() => {
            coin.removeFromParent();
            onDone();
        })
    ));

    // Spin while flying
    coin.runAction(cc.rotateBy(0.6, 720));
}

// Usage: collect 5 coins
for (let i = 0; i < 5; i++) {
    const delay = i * 0.1;
    this.scheduleOnce(() => {
        collectCoin(this, cc.p(200, 100), cc.p(400, 290), () => {
            this.coinCount++;
            this.updateCoinLabel();
        });
    }, delay);
}
```

Build an Animation from sprite frames and run it:

```typescript
// Load sprite frames (assumes plist is loaded)
const frames: cc.SpriteFrame[] = [];
for (let i = 1; i <= 8; i++) {
    const name = 'hero_walk_' + i.toString().padStart(2, '0') + '.png';
    const frame = cc.spriteFrameCache.getSpriteFrame(name);
    if (frame) frames.push(frame);
}

const walkAnim = new cc.Animation(frames, 0.08); // 0.08s per frame
walkAnim.setRestoreOriginalFrame(true);

const hero = new cc.Sprite(frames[0]);
hero.setPosition(100, 100);
this.addChild(hero);

// Play walk animation looping
const walkAction = cc.repeatForever(cc.animate(walkAnim));
walkAction.setTag(1);
hero.runAction(walkAction);

// Stop walking later
hero.stopActionByTag(1);
```

Scale X to 0, swap the texture, then scale back:

```typescript
function flipCard(card: cc.Sprite, frontTexture: string, backTexture: string): void {
    const isShowingFront = card.getUserData()?.showingFront ?? false;
    const newTexture = isShowingFront ? backTexture : frontTexture;

    card.runAction(cc.sequence(
        cc.scaleTo(0.15, 0, 1).easing(cc.easeIn(2)),
        cc.callFunc(() => {
            card.setTexture(newTexture);
            card.setUserData({ showingFront: !isShowingFront });
        }),
        cc.scaleTo(0.15, 1, 1).easing(cc.easeOut(2))
    ));
}

const card = new cc.Sprite('card_back.png');
card.setPosition(200, 200);
card.setUserData({ showingFront: false });
this.addChild(card);

// Flip on tap
flipCard(card, 'card_front.png', 'card_back.png');
```

Create an expanding, fading ring:

```typescript
function createShockwave(parent: cc.Node, pos: cc.Point): void {
    const ring = new cc.Sprite('ring.png');
    ring.setPosition(pos);
    ring.setScale(0.1);
    ring.setOpacity(255);
    parent.addChild(ring, 50);

    ring.runAction(cc.sequence(
        cc.spawn(
            cc.scaleTo(0.6, 3.0).easing(cc.easeOut(2)),
            cc.fadeOut(0.6)
        ),
        cc.removeSelf()
    ));
}

// Multiple rings for dramatic effect
for (let i = 0; i < 3; i++) {
    this.scheduleOnce(() => {
        createShockwave(this, cc.p(240, 160));
    }, i * 0.15);
}
```

Define waypoints and use Catmull-Rom spline for smooth curves:

```typescript
const waypoints = [
    cc.p(50, 50),
    cc.p(150, 250),
    cc.p(300, 200),
    cc.p(400, 280),
    cc.p(450, 100)
];

const pathAction = cc.catmullRomTo(3.0, waypoints);
const enemy = new cc.Sprite('enemy.png');
enemy.setPosition(waypoints[0]);
this.addChild(enemy);

enemy.runAction(cc.sequence(
    pathAction,
    cc.callFunc(() => cc.log('Path complete'))
));

// Loop the path
enemy.runAction(cc.repeatForever(cc.sequence(
    cc.catmullRomTo(3.0, waypoints),
    cc.catmullRomTo(3.0, waypoints.slice().reverse())
)));
```

Catmull-Rom automatically creates smooth curves through all control points.

Animate individual letter sprites using getLetter on cc.Label:

```typescript
const label = cc.Label.createWithBMFont('res/fonts/pixel.fnt', 'LEVEL COMPLETE');
label.setPosition(240, 160);
this.addChild(label);

// Hide all letters initially
const len = label.getStringLength();
for (let i = 0; i < len; i++) {
    const letter = label.getLetter(i);
    if (letter) {
        letter.setOpacity(0);
        letter.setScale(2.0);
    }
}

// Reveal one by one
for (let i = 0; i < len; i++) {
    const letter = label.getLetter(i);
    if (letter) {
        letter.runAction(cc.sequence(
            cc.delayTime(i * 0.08),
            cc.spawn(
                cc.fadeIn(0.15),
                cc.scaleTo(0.15, 1.0).easing(cc.easeBackOut())
            )
        ));
    }
}
```

Wrap actions with cc.speed to control playback rate:

```typescript
const move = cc.moveTo(2.0, cc.p(400, 300));
const fade = cc.fadeTo(2.0, 100);
const combined = cc.spawn(move, fade);

// Normal speed
const normalAction = cc.speed(combined, 1.0);

// Slow motion (half speed)
const slowAction = cc.speed(combined.clone(), 0.5);

// Fast forward (double speed)
const fastAction = cc.speed(combined.clone(), 2.0);

node.runAction(normalAction);

// Change speed dynamically
normalAction.setSpeed(0.3); // slow down
normalAction.setSpeed(1.0); // back to normal
```

`cc.speed` wraps any FiniteTimeAction and multiplies its playback rate. Use `setSpeed()` to change it at runtime for bullet-time effects.

Use a black overlay that slides across the screen:

```typescript
function wipeTransition(parent: cc.Node, onMidpoint: () => void): void {
    const winSize = cc.director.getWinSize();

    const wipe = new cc.LayerColor(cc.color(0, 0, 0, 255));
    wipe.setContentSize(winSize);
    wipe.setPosition(-winSize.width, 0);
    parent.addChild(wipe, 9999);

    wipe.runAction(cc.sequence(
        cc.moveTo(0.3, cc.p(0, 0)).easing(cc.easeIn(2)),
        cc.callFunc(() => onMidpoint()),
        cc.delayTime(0.1),
        cc.moveTo(0.3, cc.p(winSize.width, 0)).easing(cc.easeOut(2)),
        cc.removeSelf()
    ));
}

// Usage
wipeTransition(this, () => {
    // Swap scene content at midpoint (screen is fully covered)
    this.rebuildLevel();
});
```

cc.targetedAction lets you run an action targeting a specific node within a sequence:

```typescript
const player = this.getChildByName('player');
const enemy = this.getChildByName('enemy');

// Player attacks, then enemy reacts
player.runAction(cc.sequence(
    cc.moveTo(0.3, cc.p(enemy.x - 50, enemy.y)),
    cc.targetedAction(enemy, cc.sequence(
        cc.tintTo(0.1, 255, 0, 0),
        cc.moveBy(0.1, cc.p(20, 0)),
        cc.moveBy(0.1, cc.p(-20, 0)),
        cc.tintTo(0.2, 255, 255, 255)
    )),
    cc.moveTo(0.3, cc.p(100, player.y))
));
```

This is useful in cutscenes or combat sequences where multiple nodes need coordinated animation from one action sequence.

Use repeating scale with sine easing:

```typescript
// Gentle pulse
