)));
```

Use jumpBy for parabolic projectile paths:

```typescript
function fireProjectile(
    parent: cc.Node, from: cc.Point, to: cc.Point,
    height: number, onHit: () => void
): void {
    const bullet = new cc.Sprite('fireball.png');
    bullet.setPosition(from);
    parent.addChild(bullet, 10);

    const dx = to.x - from.x;
    const dy = to.y - from.y;
    const dist = Math.sqrt(dx * dx + dy * dy);
    const duration = dist / 400; // speed

    bullet.runAction(cc.sequence(
        cc.spawn(
            cc.jumpBy(duration, cc.p(dx, dy), height, 1),
            cc.rotateBy(duration, 360 * 2)
        ),
        cc.callFunc(() => {
            bullet.removeFromParent();
            onHit();
        })
    ));
}

fireProjectile(this, cc.p(50, 100), cc.p(350, 100), 120, () => {
    cc.log('Hit!');
});
```

Animate a sprite along chained bezier segments:

```typescript
const targets = [cc.p(100, 200), cc.p(250, 150), cc.p(350, 250), cc.p(450, 100)];
const bolt = new cc.Sprite('lightning_ball.png');
bolt.setPosition(targets[0]);
bolt.setScale(0.5);
this.addChild(bolt, 50);

const segments: cc.FiniteTimeAction[] = [];
for (let i = 0; i < targets.length - 1; i++) {
    const from = targets[i];
    const to = targets[i + 1];
    const midY = Math.max(from.y, to.y) + 50 + Math.random() * 50;
    const cp = cc.p((from.x + to.x) / 2, midY);

    segments.push(cc.bezierTo(0.15, [cp, cp, to]));
    segments.push(cc.callFunc(() => {
        // Flash effect at each target
        const flash = new cc.Sprite('flash.png');
        flash.setPosition(to);
        this.addChild(flash, 49);
        flash.runAction(cc.sequence(cc.fadeOut(0.2), cc.removeSelf()));
    }));
}

segments.push(cc.removeSelf());
bolt.runAction(cc.sequence(segments));
```

