Use cc.actionTween to animate any named property:

```typescript
const bar = this.getChildByName('progressBar');
bar.progress = 0;
bar.updateTweenAction = function(value: number, key: string) {
    if (key === 'progress') {
        this.progress = value;
        // Update visual (e.g., scale or clip)
        this.setScaleX(value / 100);
    }
};

bar.runAction(cc.actionTween(3.0, 'progress', 0, 100).easing(cc.easeSineInOut()));
```

The target node must implement `updateTweenAction(value, key)` or the property must exist on the node.

