instruction:
Review this code:

```typescript
const action = cc.moveTo(1, cc.p(300, 300));
action.setDuration(0.5);
action.easing(cc.easeBackOut());
node.runAction(action);
```

output:
**Issue:** `setDuration(0.5)` overrides the original 1-second duration, which may be intentional but is confusing. More importantly, `.easing()` returns a new action — the result is not captured, so the easing is NOT applied.

**Fix:**

```typescript
const action = cc.moveTo(0.5, cc.p(300, 300)).easing(cc.easeBackOut());
node.runAction(action);
```

Or if you need to change duration:
```typescript
const action = cc.moveTo(1, cc.p(300, 300));
action.setDuration(0.5);
const eased = action.easing(cc.easeBackOut());
node.runAction(eased);
```

Always capture the return value of `.easing()`.

Use scheduling with trigonometry since there's no built-in orbit action:

```typescript
function orbitAction(node: cc.Node, center: cc.Point, radius: number, duration: number): void {
    let angle = 0;
    const speed = (Math.PI * 2) / duration;

    node.schedule((dt: number) => {
        angle += speed * dt;
        node.x = center.x + Math.cos(angle) * radius;
        node.y = center.y + Math.sin(angle) * radius;
    }, 0, cc.macro.REPEAT_FOREVER, 0, 'orbit');
}

const satellite = new cc.Sprite('planet.png');
satellite.setPosition(340, 160);
this.addChild(satellite);
orbitAction(satellite, cc.p(240, 160), 100, 3.0); // 3-second orbit
```

Use ProgressTimer with a radial fill:

```typescript
const timerBg = new cc.Sprite('timer_bg.png');
timerBg.setPosition(240, 160);
this.addChild(timerBg);

const timer = new cc.ProgressTimer(new cc.Sprite('timer_fill.png'));
timer.setType(cc.ProgressTimer.TYPE_RADIAL);
timer.setReverseDirection(true);
timer.setMidpoint(cc.p(0.5, 0.5));
timer.setPosition(240, 160);
timer.setPercentage(100);
this.addChild(timer);

// Countdown from 100% to 0% over 30 seconds
timer.runAction(cc.sequence(
    cc.progressFromTo(30.0, 100, 0),
    cc.callFunc(() => this.onTimerExpired())
));
```

Chain complex action patterns:

```typescript
function bossAttackSequence(boss: cc.Sprite, target: cc.Point): void {
    const startPos = boss.getPosition();

    boss.runAction(cc.sequence(
        // Charge up - glow and grow
        cc.spawn(
            cc.scaleTo(0.5, 1.3).easing(cc.easeSineIn()),
            cc.tintTo(0.5, 255, 100, 100)
        ),
        // Dash at target
        cc.moveTo(0.2, target).easing(cc.easeIn(3)),
        // Impact - shake
        cc.callFunc(() => shakeScreen(boss.getParent())),
        cc.spawn(
            cc.scaleTo(0.1, 1.5),
            cc.tintTo(0.1, 255, 255, 255)
        ),
        // Recover
        cc.delayTime(0.3),
        cc.spawn(
            cc.moveTo(0.5, startPos).easing(cc.easeOut(2)),
            cc.scaleTo(0.3, 1.0)
        )
    ));
}

function shakeScreen(layer: cc.Node): void {
    const orig = layer.getPosition();
    const shakes: cc.FiniteTimeAction[] = [];
    for (let i = 0; i < 6; i++) {
        shakes.push(cc.moveTo(0.04, cc.p(
            orig.x + (Math.random() - 0.5) * 16,
            orig.y + (Math.random() - 0.5) * 16
        )));
    }
    shakes.push(cc.moveTo(0.04, orig));
    layer.runAction(cc.sequence(shakes));
}
```

